exports.push([module.id, "\ntd {\r\n    color: #000;\n}\r\n", "", {"version":3,"sources":["D:/laragon/www/sdrimsac-tenant/resources/js/views/sale_notes/resources/js/views/sale_notes/index.vue"],"names":[],"mappings":";AAigBA;IACA,YAAA;CACA","file":"index.vue","sourcesContent":["<!-- Modulo de Notas de Venta -->\r\n<template>\r\n    <div>\r\n        <div class=\"container-fluid p-l-0 p-r-0\">\r\n            <div class=\"page-header\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-sm-6\">\r\n                        <h6><span>Comprobante Nota de Venta</span></h6>\r\n                        <ol class=\"breadcrumb\">\r\n                            <li class=\"breadcrumb-item\">\r\n                                <a href=\"/dashboard\">Dashbodard</a>\r\n                            </li>\r\n                            <li class=\"breadcrumb-item active\">\r\n                                <span class=\"text-muted\">Nota de Venta</span>\r\n                            </li>\r\n                        </ol>\r\n                    </div>\r\n\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <!-- Container-fluid starts-->\r\n        <div class=\"container-fluid p-l-0 p-r-0\">\r\n            <div class=\"card mb-0\">\r\n                <div class=\"card-header bg-primary\">\r\n                    <h4 class=\"my-0 text-white\">\r\n                        <i class=\"fas fa-file-alt\"></i>\r\n                        Consulta de Nota de venta</h4>\r\n                </div>\r\n                <div class=\"data-table-visible-columns\">\r\n                        <el-button \r\n                                    class=\"\" \r\n                                    href=\"javascript:void(0)\" \r\n                                    @click.prevent=\"clickCreate()\">\r\n                                   \r\n                                <i class=\"fas fa-file-alt fa-lg\"></i>\r\n                                <i class=\"fas fa-plus\"></i>\r\n                                Nuevo NV\r\n                        </el-button>\r\n                        <el-button  @click.prevent=\"onOpenModalGenerateCPE\"\r\n                                v-if=\"just_sale_notes\"\r\n                                type=\"button\">\r\n                                <i class=\"fas fa-file-check\"></i> \r\n                                Generar CPE de Multiples NV\r\n                        </el-button>\r\n                </div> \r\n\r\n\r\n                <!-- <div class=\"col-12 text-end\">\r\n                    <el-dropdown :hide-on-click=\"false\">\r\n                        <el-button type=\"primary\">\r\n                            Mostrar/Ocultar columnas<i\r\n                                class=\"el-icon-arrow-down el-icon--right\"\r\n                            ></i>\r\n                        </el-button>\r\n                        <el-dropdown-menu slot=\"dropdown\">\r\n                            <el-dropdown-item\r\n                                v-for=\"(column, index) in columns\"\r\n                                :key=\"index\"\r\n                            >\r\n                                <el-checkbox v-model=\"column.visible\">{{\r\n                                    column.title\r\n                                }}</el-checkbox>\r\n                            </el-dropdown-item>\r\n                        </el-dropdown-menu>\r\n                    </el-dropdown>\r\n                </div> -->\r\n                <div class=\"card-body\">\r\n                    <data-table :resource=\"resource\">\r\n                        <tr slot=\"heading\" class=\"bg-primary\">\r\n                            <th>#</th>\r\n                            <th class=\"text-white text-end\">Acciones</th>\r\n                            <th class=\"text-white text-center\">Fecha Emisión</th>\r\n                            <th class=\"text-end text-white\">Vendedor</th>\r\n                            <th class=\"text-end text-white\">Cliente</th>\r\n                            <th class=\"text-end text-white\">Nota de Venta</th>\r\n                            <th class=\"text-end text-white\">Guia</th>\r\n                            <th class=\"text-end text-white\">Estado</th>\r\n                            <th class=\"text-white text-center\">Moneda</th>\r\n                            <th class=\"text-white text-end\" v-if=\"columns.total_exportation.visible\">T.Exportación</th>\r\n                            <th class=\"text-white text-end\" v-if=\"columns.total_free.visible\"> T.Gratuito</th>\r\n                            <th class=\"text-white text-end\"v-if=\"columns.total_unaffected.visible\">T.Inafecta</th>\r\n                            <th class=\"text-white ext-end\" v-if=\"columns.total_exonerated.visible\"> T.Exonerado</th>\r\n                            <th class=\"text-white text-end\" v-if=\"columns.total_taxed.visible\">T.Gravado</th>\r\n                            <th class=\"text-white text-end\" v-if=\"columns.total_igv.visible\">T.Igv</th>\r\n                            <th class=\"text-white text-center\">Adelanto</th>\r\n                            <th class=\"text-white text-center\">Metodo de pago</th>\r\n                            <th class=\"text-white text-center\">Pagado</th>\r\n                            <th class=\"text-white text-center\">Resta</th>\r\n                            <th class=\"text-white text-end\">Total</th>\r\n                            <th class=\"text-white text-end\">Tasa</th>\r\n                            <th class=\"text-white text-center\">Comprobantes</th>\r\n                            <th class=\"text-white text-center\">Estado pago</th>\r\n                            <th class=\"text-white text-center\">Acciones crédito</th>\r\n                        </tr>\r\n\r\n                        <tr></tr>\r\n                        <tr slot-scope=\"{ index, row }\">\r\n                            <td>{{ index }}</td>\r\n                            <td class=\"text-end\">\r\n                                <div\r\n                                    v-if=\"row.state_type_id != 11\"\r\n                                    class=\"btn-toolbar mb-2\"\r\n                                    role=\"toolbar\">\r\n                                    <div class=\"btn-group mb-1\">\r\n                                        <button\r\n                                            class=\"btn btn-secondary btn-sm dropdown-toggle\"\r\n                                            type=\"button\"\r\n                                            data-bs-toggle=\"dropdown\"\r\n                                            aria-haspopup=\"true\"\r\n                                            aria-expanded=\"false\">\r\n                                            <i class=\"fas fa-ellipsis-v\"></i>\r\n                                        </button>\r\n                                        <div\r\n                                            class=\"dropdown-menu dropdown-menu-sm\">\r\n                                            <a\r\n                                                href=\"!#\"\r\n                                                v-if=\"\r\n                                                    row.state_type_id != '11' &&\r\n                                                        (user_type == 'admin' ||\r\n                                                            user_type ==\r\n                                                                'superadmin')\"\r\n                                                class=\"dropdown-item\"\r\n                                                @click.prevent=\"clickDetail(row)\">\r\n                                                <i class=\"fas fa-trash\"></i>\r\n                                                Ver detalle\r\n                                            </a>\r\n                                            <a :href=\" `/dispatches/create_new/sale_note/${row.id}`\"\r\n                                                v-if=\" row.state_type_id != '11' && (user_type == 'admin' || user_type ==\r\n                                                'superadmin')\" class=\"dropdown-item\">\r\n                                                <i class=\"far fa-file-alt\"></i>\r\n                                                Generar guía\r\n                                            </a>\r\n                                            <a\r\n                                                href=\"!#\"\r\n                                                v-if=\"\r\n                                                    row.state_type_id != '11' &&\r\n                                                        (user_type == 'admin' ||\r\n                                                            user_type ==\r\n                                                                'superadmin')\r\n                                                \"\r\n                                                class=\"dropdown-item\"\r\n                                                @click.prevent=\"\r\n                                                    clickVoided(row.id)\r\n                                                \"\r\n                                                ><i class=\"fas fa-trash\"></i>\r\n                                                Anular Nota de Venta\r\n                                            </a>\r\n                                            <!-- <div\r\n                                                class=\"dropdown-divider\"\r\n                                                v-if=\"\r\n                                                    row.state_type_id != '11' &&\r\n                                                        (user_type == 'admin' ||\r\n                                                            user_type ==\r\n                                                                'superadmin')\r\n                                                \"\r\n                                            ></div> -->\r\n                                            <a\r\n                                                href=\"!#\"\r\n                                                class=\"dropdown-item\"\r\n                                                @click.prevent=\"\r\n                                                    clickCreate(row.id)\r\n                                                \"\r\n                                                v-if=\"\r\n                                                    row.btn_generate &&\r\n                                                        row.state_type_id !=\r\n                                                            '11' &&\r\n                                                        (user_type == 'admin' ||\r\n                                                            user_type ==\r\n                                                                'superadmin')\r\n                                                \"\r\n                                            >\r\n                                                <i\r\n                                                    class=\"fas fa-file-signature\"\r\n                                                ></i>\r\n                                                Editar nota de Venta\r\n                                            </a>\r\n                                            <!-- <div\r\n                                                class=\"dropdown-divider\"\r\n                                                v-if=\"\r\n                                                    row.state_type_id != '11' &&\r\n                                                        (user_type == 'admin' ||\r\n                                                            user_type ==\r\n                                                                'superadmin')\r\n                                                \"\r\n                                            ></div> -->\r\n                                            <a\r\n                                                href=\"!#\"\r\n                                                class=\"dropdown-item\"\r\n                                                @click.prevent=\"\r\n                                                    clickGenerate(row.id)\r\n                                                \"\r\n                                                v-if=\"\r\n                                                    !row.changed &&\r\n                                                        row.state_type_id !=\r\n                                                            '11' &&\r\n                                                        soapCompany != '03' &&\r\n                                                        (user_type == 'admin' ||\r\n                                                            user_type ==\r\n                                                                'superadmin')\r\n                                                \"\r\n                                            >\r\n                                                <i\r\n                                                    class=\"fas fa-file-excel\"\r\n                                                ></i>\r\n                                                Generar Comprobante\r\n                                            </a>\r\n                                            <!-- <div\r\n                                                class=\"dropdown-divider\"\r\n                                                v-if=\"\r\n                                                    row.state_type_id != '11' &&\r\n                                                        (user_type == 'admin' ||\r\n                                                            user_type ==\r\n                                                                'superadmin')\r\n                                                \"\r\n                                            ></div> -->\r\n                                            <a\r\n                                                href=\"!#\"\r\n                                                v-if=\"row.state_type_id != '11'\"\r\n                                                class=\"dropdown-item\"\r\n                                                @click.prevent=\"\r\n                                                    clickOptions(row.id)\r\n                                                \"\r\n                                                ><i class=\"fas fa-print\"></i>\r\n                                                Imprimir Nota de Venta\r\n                                            </a>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                            </td>\r\n\r\n                            <td class=\"text-center\">\r\n                                {{ row.date_of_issue }}\r\n                                <template>\r\n                                    <br />\r\n                                    <small>\r\n                                        {{ row.time_of_issue }}\r\n                                    </small>\r\n                                </template>\r\n                            </td>\r\n                            <td>{{ row.user_name }}</td>\r\n                            <td>\r\n                                {{ row.customer_name }}<br /><small\r\n                                    v-text=\"row.customer_number\"\r\n                                ></small>\r\n                            </td>\r\n\r\n                            <td>{{ row.full_number }}</td>\r\n                            <td>\r\n                                <span\r\n                                    v-for=\"(dispatch, idx) in row.dispatches\"\r\n                                    :key=\"idx\"\r\n                                >\r\n                                    {{ dispatch.number_full }} <br />\r\n                                </span>\r\n                            </td>\r\n                            <td>{{ row.state_type_description }}</td>\r\n                            <td class=\"text-center\">\r\n                                {{ row.currency_type_id }}\r\n                            </td>\r\n                            <td\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_exportation.visible\"\r\n                            >\r\n                                {{ row.total_exportation }}\r\n                            </td>\r\n                            <td\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_free.visible\"\r\n                            >\r\n                                {{ row.total_free }}\r\n                            </td>\r\n                            <td\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_unaffected.visible\"\r\n                            >\r\n                                {{ row.total_unaffected }}\r\n                            </td>\r\n                            <td\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_exonerated.visible\"\r\n                            >\r\n                                {{ row.total_exonerated }}\r\n                            </td>\r\n                            <td\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_taxed.visible\"\r\n                            >\r\n                                {{ row.total_taxed }}\r\n                            </td>\r\n                            <td\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.total_igv.visible\"\r\n                            >\r\n                                {{ row.total_igv }}\r\n                            </td>\r\n\r\n                            <td\r\n                                class=\"text-center\"\r\n                                v-if=\"columns.total_paid.visible\"\r\n                            >\r\n                                {{ row.total_paid }}\r\n                            </td>\r\n                            <td>\r\n                                {{ row.advances }}\r\n                            </td>\r\n                            <!-- <td>\r\n                                {{ row.advances }}\r\n                            </td> -->\r\n                            <!-- <template v-if=\"row.total_pending_paid > 0\">\r\n                                <td\r\n                                    class=\"text-center text-danger font-weight-bold\"\r\n                                >\r\n                                    {{ row.total_pending_paid }}\r\n                                </td>\r\n                            </template>\r\n                            <template v-else>\r\n                                <td class=\"text-end\"></td>\r\n                            </template> -->\r\n                            <td>\r\n                                <div\r\n                                    class=\"justify-content-center d-flex flex-column\"\r\n                                >\r\n                                    <el-tag\r\n                                        style=\"margin-top:5px;\"\r\n                                        v-for=\"(data, idx) in row.boxes\r\n                                            .slice(-3)\r\n                                            .reverse()\"\r\n                                        :key=\"idx\"\r\n                                        type=\"primary\"\r\n                                    >\r\n                                        <b\r\n                                            >{{ data.method }} S/{{\r\n                                                data.amount\r\n                                            }}</b\r\n                                        >\r\n                                    </el-tag>\r\n                                </div>\r\n                            </td>\r\n                            <!-- <template v-if=\"row.total_payment != null || row.total_payment != 0\">\r\n                                <td class=\"text-end\">\r\n                                    {{ row.total }}\r\n                                </td>\r\n                            </template> -->\r\n                            <td class=\"text-end\">\r\n                                {{ row.paid_amount.toFixed(2) }}\r\n                            </td>\r\n                            <td class=\"text-end\">\r\n                                {{ row.pending.toFixed(2) }}\r\n                            </td>\r\n                            <template>\r\n                                <td class=\"text-end\">\r\n                                    {{ Number(row.total).toFixed(2) }}\r\n                                </td>\r\n                            </template>\r\n                            <td class=\"text-end\">\r\n                                {{\r\n                                    row.tax_rate > 0 ? `${row.tax_rate}%` : \"-\"\r\n                                }}\r\n                            </td>\r\n                            <td>\r\n                                <template\r\n                                    v-for=\"(document, i) in row.documents\"\r\n                                >\r\n                                    <label\r\n                                        ::key=\"i\"\r\n                                        v-text=\"document.number_full\"\r\n                                        class=\"d-block\"\r\n                                    ></label>\r\n                                </template>\r\n                            </td>\r\n                            <td class=\"text-center\">\r\n                                <span\r\n                                    class=\"badge text-white\"\r\n                                    :class=\"{\r\n                                        'bg-success': row.paid,\r\n                                        'bg-warning': !row.paid\r\n                                    }\"\r\n                                    v-if=\"\r\n                                        row.state_type_description !=\r\n                                            'Anulado' && row.total > 0\r\n                                    \"\r\n                                    >{{\r\n                                        row.paid ? \"Pagado\" : \"Pendiente\"\r\n                                    }}</span\r\n                                >\r\n                                <span\r\n                                    class=\"badge text-white bg-danger\"\r\n                                    v-if=\"\r\n                                        row.state_type_description !=\r\n                                            'Registrado'\r\n                                    \"\r\n                                    >Anulado</span\r\n                                >\r\n                                <span\r\n                                    class=\"badge text-white bg-success\"\r\n                                    v-if=\"row.total == 0\"\r\n                                    >Pagado</span\r\n                                >\r\n                            </td>\r\n\r\n                            <td class=\"text-center\">\r\n                                <!-- <button\r\n                                    type=\"button\"\r\n                                    style=\"min-width: 41px\"\r\n                                    class=\"btn waves-effect waves-light btn-sm btn-info m-1__2\"\r\n                                    @click.prevent=\"clickPayment(row.id)\"\r\n                                    v-if=\"row.btn_payments\"\r\n                                >\r\n                                    Pagos\r\n                                </button> -->\r\n\r\n                                <template v-if=\"row.is_credit\">\r\n                                    <el-tooltip\r\n                                        class=\"item\"\r\n                                        effect=\"dark\"\r\n                                        content=\"Registrar Pagos\"\r\n                                        placement=\"bottom-end\"\r\n                                    >\r\n                                        <button\r\n                                            type=\"button\"\r\n                                            class=\"btn waves-effect waves-light btn-sm btn-primary\"\r\n                                            v-if=\"row.state_type_id != '11'\"\r\n                                            @click.prevent=\"\r\n                                                clickPayment(row.id)\r\n                                            \"\r\n                                        >\r\n                                            <i\r\n                                                class=\"fas fa-money-bill-alt\"\r\n                                            ></i>\r\n                                        </button>\r\n                                    </el-tooltip>\r\n\r\n                                    <el-tooltip\r\n                                        class=\"item\"\r\n                                        effect=\"dark\"\r\n                                        content=\"Imprimir Contrato\"\r\n                                        placement=\"bottom-end\"\r\n                                    >\r\n                                        <button\r\n                                            type=\"button\"\r\n                                            class=\"btn waves-effect waves-light btn-sm btn-success\"\r\n                                            @click.prevent=\"\r\n                                                clickContract(row.id)\r\n                                            \"\r\n                                        >\r\n                                            <i class=\"fas fa-file-alt\"></i>\r\n                                        </button>\r\n                                    </el-tooltip>\r\n                                    <el-tooltip\r\n                                        class=\"item\"\r\n                                        effect=\"dark\"\r\n                                        content=\"Imprimir Cronograma de Pagos\"\r\n                                        placement=\"bottom-end\"\r\n                                    >\r\n                                        <button\r\n                                            type=\"button\"\r\n                                            class=\"btn waves-effect waves-light btn-sm btn-success\"\r\n                                            @click.prevent=\"\r\n                                                clickSchedule(row.id)\r\n                                            \"\r\n                                        >\r\n                                            <i class=\"fas fa-file-alt\"></i>\r\n                                        </button>\r\n                                    </el-tooltip>\r\n                                </template>\r\n                            </td>\r\n\r\n                            <td\r\n                                class=\"text-end\"\r\n                                v-if=\"columns.paid.visible && row.total > 0\"\r\n                            >\r\n                                {{ row.paid ? \"Pagado\" : \"Pendiente\" }}\r\n                            </td>\r\n                        </tr>\r\n                    </data-table>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <sale-note-payments\r\n            :showDialog.sync=\"showDialogPayments\"\r\n            :configuration.sync=\"configuration\"\r\n            :documentId=\"recordId\"\r\n        ></sale-note-payments>\r\n\r\n        <sale-notes-options\r\n            :showDialog.sync=\"showDialogOptions\"\r\n            :recordId.sync=\"saleNotesNewId\"\r\n            :configuration.sync=\"configuration\"\r\n            :editSale.sync=\"editSale\"\r\n            :showClose=\"true\"\r\n            :company=\"company\"\r\n        ></sale-notes-options>\r\n\r\n        <sale-note-generate\r\n            :showDialog.sync=\"showDialogGenerate\"\r\n            :recordId=\"recordId\"\r\n            :showGenerate=\"true\"\r\n            :showClose=\"false\"\r\n        ></sale-note-generate>\r\n        <sale-note-detail\r\n            :number=\"currentNumber\"\r\n            :saleNoteId=\"recordId\"\r\n            :showDialog.sync=\"showDialogDetail\"\r\n            :boxes=\"boxes\"\r\n        >\r\n        </sale-note-detail>\r\n        <modal-generate-cpe\r\n            :show.sync=\"showModalGenerateCPE\"\r\n        ></modal-generate-cpe>\r\n    </div>\r\n</template>\r\n<style>\r\ntd {\r\n    color: #000;\r\n}\r\n</style>\r\n<script>\r\nimport DataTable from \"../../components/DataTableSaleNote.vue\";\r\n//'../../components/DataTableSaleNote.vue'\r\nimport SaleNotePayments from \"./partials/payments.vue\";\r\nimport SaleNotesOptions from \"./partials/options.vue\";\r\nimport SaleNoteGenerate from \"./partials/option_documents\";\r\nimport SaleNoteDetail from \"./partials/detail.vue\";\r\nimport { deletable } from \"../../mixins/deletable\";\r\nimport ModalGenerateCpe from \"./ModalGenerateCPE\";\r\nexport default {\r\n    props: [\r\n        \"just_sale_notes\",\r\n        \"soapCompany\", \"company\", \"configuration\", \"user_type\"],\r\n    mixins: [deletable],\r\n    components: {\r\n        Moda